29	static void putchunk(fz_context *ctx, fz_output *out, char *tag, unsigned char *data, size_t size)
30	{
31		unsigned int sum;
32	
33		if ((uint32_t)size != size)
34			fz_throw(ctx, FZ_ERROR_LIMIT, "PNG chunk too large");
35	
36		fz_write_int32_be(ctx, out, (int)size);
37		fz_write_data(ctx, out, tag, 4);
38		fz_write_data(ctx, out, data, size);
39		sum = crc32(0, NULL, 0);
40		sum = crc32(sum, (unsigned char*)tag, 4);
41		sum = crc32(sum, data, (unsigned int)size);
42		fz_write_int32_be(ctx, out, sum);
43	}
